column6:
{
  "note": "Needed to swap sriracha with similarly flavored hot sauces that are commonly stocked in North American grocery stores.",
  "alts": [
    {
      "name_en": "Cholula Hot Sauce (Red)",
      "match": "Similar",
      "desc": "A tangy, chili-forward hot sauce with a mild-to-medium kick that works well as a sriracha substitute for drizzling or mixing into sauces.",
      "where": "International foods / hot sauce aisle"
    },
    {
      "name_en": "Frank’s RedHot (Original)",
      "match": "Different but works",
      "desc": "A slightly thinner cayenne-based hot sauce with a vinegar tang that adds heat and flavor to the same dishes where you’d use sriracha.",
      "where": "Hot sauce aisle"
    },
    {
      "name_en": "Huy Fong Foods Garlic Chili Sauce (similar style)",
      "match": "Very close",
      "desc": "A very close chili-garlic style option with a comparable spicy-sweet chili profile depending on the specific product variety.",
      "where": "Asian foods aisle (often near other chili sauces)"
    },
    {
      "name_en": "Lee Kum Kee Chili Garlic Sauce",
      "match": "Similar",
      "desc": "A chili-garlic condiment that’s thicker and more aromatic, giving a sriracha-like kick for stir-fries, noodles, and marinades.",
      "where": "Asian foods aisle (condiments/sauces section)"
    }
  ]
}

{
  "note": "You need lactose-free or reduced-lactose options so you can still cook and bake without triggering symptoms.",
  "alts": [
    {
      "name_en": "Lactose-Free Butter",
      "match": "Very close",
      "desc": "Butter made with lactase added so the lactose is broken down while keeping a similar taste and texture to regular butter.",
      "where": "Dairy aisle, near regular butter (often labeled lactose-free or lactose-reduced)."
    },
    {
      "name_en": "Ghee (Clarified Butter)",
      "match": "Similar",
      "desc": "Butterfat with milk solids removed, making it typically much lower in lactose and easier for many lactose-intolerant people to tolerate.",
      "where": "International foods aisle or near specialty oils/ghee, or sometimes in the dairy aisle."
    },
    {
      "name_en": "Vegan Butter (Plant-Based)",
      "match": "Different but works",
      "desc": "Butter alternatives made from plant oils that are naturally lactose-free and can work well for spreading and most cooking/baking.",
      "where": "Dairy-free/vegan section in the refrigerated aisle (often near margarine and spreads)."
    },
    {
      "name_en": "Margarine (Dairy-Free or Lactose-Free)",
      "match": "Different but works",
      "desc": "Some margarines are made without dairy ingredients and are lactose-free, making them a practical swap for spreading and everyday cooking.",
      "where": "Near butter and other spreads in the dairy section (check the label for 'dairy-free' or 'lactose-free')."
    }
  ]
}

{
  "note": "You need alternatives to rice vinegar so you can still achieve similar acidity and flavor in recipes if rice vinegar isn’t available.",
  "alts": [
    {
      "name_en": "White wine vinegar",
      "match": "Very close",
      "desc": "Milder and slightly fruity, it substitutes well for rice vinegar in dressings, marinades, and quick pickles.",
      "where": "Vinegar aisle, near other bottled vinegars."
    },
    {
      "name_en": "Apple cider vinegar",
      "match": "Similar",
      "desc": "Provides comparable tanginess with a light apple note, best for sauces, slaws, and everyday pickling.",
      "where": "Vinegar aisle or natural/organic section."
    },
    {
      "name_en": "Champagne vinegar",
      "match": "Similar",
      "desc": "Delicate and less harsh than distilled vinegars, making it a good swap for many Asian-style dishes.",
      "where": "Vinegar aisle, often near specialty vinegars."
    },
    {
      "name_en": "Distilled white vinegar",
      "match": "Different but works",
      "desc": "More sharp and neutral than rice vinegar, so it works when you dilute or balance with sugar/honey.",
      "where": "Vinegar aisle, near cleaning/drying vinegars."
    }
  ]
}

{
  "note": "You need vegetarian alternatives that provide a similar hearty, protein-forward substitute in place of chicken breast.",
  "alts": [
    {
      "name_en": "Tofu (extra-firm)",
      "match": "Similar",
      "desc": "Extra-firm tofu holds its shape well when pressed and pan-seared, giving a chicken-breast-like texture in stir-fries or cutlets.",
      "where": "Produce/ refrigerated section near packaged tofu."
    },
    {
      "name_en": "Seitan (wheat gluten)",
      "match": "Very close",
      "desc": "Seitan has a chewy, meat-like bite and absorbs marinades, making it a direct swap for sliced or breaded “cutlets.”",
      "where": "Refrigerated or refrigerated/ frozen prepared foods section (often near meat alternatives)."
    },
    {
      "name_en": "Tempeh",
      "match": "Similar",
      "desc": "Tempeh is firm and hearty with a nutty flavor that works well when marinated and pan-fried for a satisfying “breast-like” portion.",
      "where": "Refrigerated section near tofu/soy products."
    },
    {
      "name_en": "Vegetarian chicken-style products (e.g., meatless chicken cutlets/strips)",
      "match": "Very close",
      "desc": "These are designed to mimic chicken in flavor and texture, making them the easiest plug-and-play option for recipes.",
      "where": "Frozen foods or refrigerated meat-alternative aisle."
    }
  ]
}

{
  "note": "Provide Korean-friendly savory substitutes for fish sauce in North American grocery aisles.",
  "alts": [
    {
      "name_en": "Korean anchovy sauce (멸치액젓, myeolchi-aekjeot)",
      "match": "Very close|Similar|Different but works",
      "desc": "A Korean anchovy-based fermented condiment with a similar umami profile, often used in banchan, soups, and marinades.",
      "where": "International/Korean aisle near other Korean condiments or in the refrigerated/condiment section depending on store."
    },
    {
      "name_en": "Thai fish sauce (น้ำปลา, nam pla)",
      "match": "Very close|Similar|Different but works",
      "desc": "Same core ingredient category (fermented fish), giving comparable saltiness and depth for kimchi, stir-fries, and soups.",
      "where": "International aisle (Thai/SEA products) near other curry pastes and condiments."
    },
    {
      "name_en": "Oyster sauce (굴소스, gu-style oyster sauce)",
      "match": "Different but works",
      "desc": "Thicker and sweeter than fish sauce, but still adds strong savory umami for Korean-style cooking when fishiness is less critical.",
      "where": "Asian sauces section (often labeled for Chinese/Asian cooking) near soy sauce and stir-fry sauces."
    },
    {
      "name_en": "Soy sauce + small amount of anchovy paste (or anchovy-derived seasoning)",
      "match": "Different but works",
      "desc": "Soy sauce supplies salt and fermentation-like funk, while anchovy paste adds the fishy umami to approximate fish-sauce depth.",
      "where": "Soy sauce aisle plus Mediterranean pantry where anchovy paste/tubes are stocked (or international section with canned anchovies)."
    }
  ]
}
